package com.company.supervision.application.identity;import org.junit.jupiter.api.Test;import static org.assertj.core.api.Assertions.*;class AuthServiceTest{@Test void acceptsStrongPassword(){assertThatCode(()->AuthService.validatePassword("StrongPass123","admin")).doesNotThrowAnyException();}@Test void rejectsWeakAndUsernamePasswords(){assertThatThrownBy(()->AuthService.validatePassword("short","admin")).isInstanceOf(IllegalArgumentException.class);assertThatThrownBy(()->AuthService.validatePassword("adminPassword123","admin")).isInstanceOf(IllegalArgumentException.class);}}